// Curated no-key ATS boards. Extend freely — this is the shared crawl.
const B = [
  ['greenhouse','stripe'],['greenhouse','hubspot'],['greenhouse','klaviyo'],['greenhouse','airbnb'],
  ['greenhouse','databricks'],['lever','meesho'],['lever','gopuff'],['ashby','notion'],['ashby','openai'],
];
return B.map(([ats,slug]) => ({ json: { ats, slug } }));

const strip=s=>(s||'').replace(/<[^>]+>/g,' ').replace(/&[a-z]+;/gi,' ').replace(/\s+/g,' ').trim();
const out=[];
for(const it of $input.all()){const b=it.json;let rows=[];
  if(Array.isArray(b))rows=b; else if(b&&Array.isArray(b.jobs))rows=b.jobs;
  for(const j of rows){const title=j.title||j.text||'';const url=j.absolute_url||j.hostedUrl||j.applyUrl||'';
    if(!title)continue;
    out.push({json:{id:'ats:'+(j.id||url),source:'ats',title,
      company:(j.categories&&j.categories.team)||'',
      location:(j.location&&(j.location.name||j.location))||(j.categories&&j.categories.location)||'',
      url,description:strip(j.content||j.descriptionPlain||'').slice(0,3000),
      postedAt:j.updated_at||j.createdAt||null}});}}
return out;

const strip=s=>(s||'').replace(/<[^>]+>/g,' ').replace(/\s+/g,' ').trim();const out=[];
for(const it of $input.all())for(const j of ((it.json&&it.json.results)||[]))
  out.push({json:{id:'adzuna:'+j.id,source:'adzuna',title:j.title||'',
    company:(j.company&&j.company.display_name)||'',location:(j.location&&j.location.display_name)||'',
    url:j.redirect_url||'',description:strip(j.description).slice(0,3000),postedAt:j.created||null}});
return out;

const strip=s=>(s||'').replace(/<[^>]+>/g,' ').replace(/\s+/g,' ').trim();const out=[];
for(const it of $input.all()){const j=it.json; if(!j||!j.position)continue;
  out.push({json:{id:'remoteok:'+j.id,source:'remoteok',title:j.position,company:j.company||'',
    location:'Remote',url:j.url||('https://remoteok.com/l/'+j.id),
    description:strip(j.description).slice(0,3000),postedAt:j.date||null}});}
return out;

// Drop stale (>90d), keep newest per id. Emit rows for the pool upsert.
const now=Date.now(), DAY=86400000, seen=new Set(), rows=[];
for(const it of $input.all()){const j=it.json; if(!j||!j.id||seen.has(j.id))continue; seen.add(j.id);
  let ageDays=null; if(j.postedAt){const t=Date.parse(j.postedAt); if(!isNaN(t)) ageDays=Math.floor((now-t)/DAY);}
  if(ageDays!==null && ageDays>90) continue;
  rows.push({id:j.id,source:j.source,title:j.title,company:j.company,location:j.location,
    url:j.url,description:(j.description||'').slice(0,2000),posted_at:j.postedAt,
    fresh: ageDays===null? true : ageDays<=60});}
return [{json:{rows}}];

// Drop already-matched, chunk into batches of 20, prebuild each Claude request.
const user = $('Set Role Configuration').first().json;
const jobs = $('Fetch Pool Shortlist').all().map(i=>i.json).filter(j=>j&&j.id);
const sent = new Set($('Get Already Matched IDs').all().map(i=>i.json.job_id));
const fresh = jobs.filter(j=>!sent.has(j.id));
const system = [
 'You are a sharp recruiter screening roles for one candidate. Score each job 0-100 for fit.',
 'Reward the candidate\'s strengths and correct seniority; penalise domain/seniority mismatch and bad location/remote fit.',
 '=== ACCEPTABLE LOCATIONS (remote or any of these) ===', (Array.isArray(user.locations)? user.locations.join(', ') : ''), 'A role tied to a location outside this list is a mismatch — lower the score and flag it.', '=== CANDIDATE PROFILE ===', user.profile || ''].join('\n');
const tool={name:'report_scores',description:'Score each job.',input_schema:{type:'object',properties:{scores:{type:'array',
  items:{type:'object',properties:{i:{type:'number'},score:{type:'number'},fit:{type:'string'},concerns:{type:'string'}},
  required:['i','score','fit','concerns']}}},required:['scores']}};
const out=[]; const B=20;
for(let s=0;s<fresh.length;s+=B){const batch=fresh.slice(s,s+B);
  const rendered=batch.map((j,i)=>`[${i}] ${j.title} @ ${j.company||j.source} | ${j.location||'?'}\n${(j.description||'').slice(0,350)}`).join('\n\n');
  out.push({json:{batch,body:{model:'claude-haiku-4-5',max_tokens:3000,system,tools:[tool],
    tool_choice:{type:'tool',name:'report_scores'},messages:[{role:'user',content:`Score these ${batch.length} jobs.\n\n${rendered}`}]}}});}
return out.length?out:[{json:{batch:[],body:null,__empty:true}}];

// Zip each Claude response back to its batch; keep >= user's min_score.
const batches=$('Create Scoring Batches').all().map(i=>i.json);
const resps=$input.all().map(i=>i.json);
const _mn=Number($('Set Role Configuration').first().json.min_score);const min=Number.isFinite(_mn)?_mn:70;
const out=[];
batches.forEach((b,bi)=>{ if(!b.batch||!b.batch.length)return; const r=resps[bi]||{};
  let scores=[]; try{const blk=(r.content||[]).find(c=>c.type==='tool_use'); scores=(blk&&blk.input&&blk.input.scores)||[];}catch(e){}
  const by={}; for(const s of scores)by[s.i]=s;
  b.batch.forEach((j,i)=>{const s=by[i]||{};const sc=s.score??0; if(sc>=min)
    out.push({json:{...j,score:sc,fit:s.fit||'',concerns:s.concerns||''}});});});
out.sort((a,b)=>b.json.score-a.json.score);
return out.length?out:[{json:{__none:true}}];

const e=$json; const wf=(e.workflow&&e.workflow.name)||'?';
const node=(e.execution&&e.execution.lastNodeExecuted)||'?';
const msg=(e.execution&&e.execution.error&&e.execution.error.message)||'(no message)';
const url=(e.execution&&e.execution.url)||'';
return [{json:{email:{from:'Job Quest Alerts <user@example.com>',to:['user@example.com'],
  subject:`Job Quest FAILED: ${wf} @ ${node}`,
  html:`<b>${wf}</b> failed at node <b>${node}</b>.<br><pre>${msg}</pre><a href="${url}">open execution</a>`}}}];
